diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..708ef729c317 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1516,6 +1516,7 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1778,7 +1779,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   // (add (add A, 1), (sext (icmp ne A, 0))) => call umax(A, 1)
   if (match(LHS, m_Add(m_Value(A), m_One())) &&
       match(RHS, m_OneUse(m_SExt(m_OneUse(m_SpecificICmp(
-                     ICmpInst::ICMP_NE, m_Specific(A), m_ZeroInt())))))) {
+                     CmpInst::ICMP_NE, m_Specific(A), m_ZeroInt())))))) {
     Value *OneConst = ConstantInt::get(A->getType(), 1);
     Value *UMax = Builder.CreateBinaryIntrinsic(Intrinsic::umax, A, OneConst);
     return replaceInstUsesWith(I, UMax);
@@ -1789,8 +1790,8 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {

   // (~X) + (~Y) --> -2 - (X + Y)
   {
-    // To ensure we can save instructions we need to ensure that we consume both
-    // LHS/RHS (i.e they have a `not`).
+    // To ensure we can save instructions we need to ensure that both
+    // LHS/RHS have a `not`.
     bool ConsumesLHS, ConsumesRHS;
     if (isFreeToInvert(LHS, LHS->hasOneUse(), ConsumesLHS) && ConsumesLHS &&
         isFreeToInvert(RHS, RHS->hasOneUse(), ConsumesRHS) && ConsumesRHS) {
@@ -1872,6 +1873,27 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, Builder.CreateZExtOrTrunc(Ret, I.getType()));
   }

+  // Fold (lshr X, C) + (zext (X & Mask) != 0) --> (X + Mask) >> C
+  // where Mask = (1 << C) - 1
+  const APInt *CInt;
+  Value *AndVal;
+  if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(A), m_APInt(CInt))),
+                         m_OneUse(m_ZExt(m_OneUse(m_ICmp(
+                             ICmpInst::ICMP_NE,
+                             m_CombineAnd(m_OneUse(m_And(m_Deferred(A),
+                                                         m_SpecificIntAllowPoison(
+                                                             (1 << CInt->getZExtValue()) - 1))),
+                                          m_Value(AndVal)),
+                             m_ZeroInt())))))) {
+    unsigned ShiftAmt = CInt->getZExtValue();
+    unsigned BitWidth = A->getType()->getScalarSizeInBits();
+    if (ShiftAmt < BitWidth) {
+      APInt Mask = APInt::getLowBitsSet(BitWidth, ShiftAmt);
+      Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), Mask));
+      return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, ShiftAmt));
+    }
+  }
+
   if (Instruction *Res = foldSquareSumInt(I))
     return Res;

@@ -1893,6 +1915,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Eliminate an op from a linear interpolation (lerp) pattern.
 static Instruction *factorizeLerp(BinaryOperator &I,
                                   InstCombiner::BuilderTy &Builder) {
